def step(self, action):
    x, y = self.state
    if action == 'up':
        x = max(x - 1, 0)
    elif action == 'down':
        x = min(x + 1, self.grid_size[0] - 1)
    elif action == 'left':
        y = max(y - 1, 0)
    elif action == 'right':
        y = min(y + 1, self.grid_size[1] - 1)
    self.state = (x, y)
    return self.state

def get_reward(self):
